srcDoc.css:
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&display=swap");
.title-container {
  text-align: center;
}

.line-container {
  position: relative;
  display: inline-block;
}

.background-bar {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, 10%);
  width: 100%;
  height: 1em;
  background-color: #E1F9B7;
  z-index: 0;
  border-radius: 4px;
}

.styled-title {
  font-family: "Poppins", sans-serif;
  font-size: 28px;
  font-weight: bold;
  color: #2C3034;
  position: relative;
  z-index: 1;
  margin: 0;
}

